    96→	pci_set_master(pdev);
    97→
    98→	err = dma_set_mask_and_coherent(&pdev->dev,
    99→					DMA_BIT_MASK(NFP_NET_MAX_DMA_BITS));
   100→	if (err)
   101→		goto err_pci_regions;
