   169→	startq = readl(ctrl_bar + NFP_NET_CFG_START_TXQ);
   170→	tx_bar_off = NFP_PCIE_QUEUE(startq);
   171→	startq = readl(ctrl_bar + NFP_NET_CFG_START_RXQ);
   172→	rx_bar_off = NFP_PCIE_QUEUE(startq);
